def parse_args() -> argparse.Namespace:
    _default_config = str(_PROJECT_ROOT / "config" / "config.yaml")
    parser = argparse.ArgumentParser(
        description="Real-Time Glasses Detection System",
        formatter_class=argparse.ArgumentDefaultsHelpFormatter,
    )
    parser.add_argument(
        "--config", default=_default_config,
        help="Path to YAML configuration file",
    )
    parser.add_argument(
        "--source", default=None,
        help="Camera source: webcam index (0, 1, …) or RTSP URL",
    )
    parser.add_argument(
